head.script:
scwin.cur_unitState = "02";
scwin.loUpperLobranCd = "";

scwin.onpageload = function() {
    scwin.loUpperLobranCd = $c.ses.getLoUpperLobranCd();
    if (scwin.loUpperLobranCd == null) {
        scwin.loUpperLobranCd = "";
    }

    $c.sbm.execute(sbm_lobranCd);

    lc_branch.setFocus();

    scwin.f_UnitChage(1);
};

scwin.onUdcCompleted = function() {
    scwin.f_setDefaultData();
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([tb_mainData]))) return;
    await scwin.f_validateDate();
};

scwin.f_setDefaultData = function() {
    ed_term1From.setValue("1");
    ed_term1To.setValue("5");
    ed_term2From.setValue("6");
    ed_term2To.setValue("10");
    ed_term3From.setValue("11");
    ed_term3To.setValue("30");
    ed_term4From.setValue("30");

    lc_con_accfCargoStd.setSelectedIndex(0);
    rd_cls.setValue("1");

    scwin.f_clsCondRdoShowHide();
};

scwin.f_InitObjects = function() {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_setDefaultData();
    scwin.f_columnShowHide();
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            udc_yard.ilCommonPopUp(scwin.callbackYard,
                pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null,
                pAllSearch, "장치장,장치장코드,장치장명");
            break;
        case 2:
            udc_stockClnt.ilCommonPopUp(scwin.callbackStockClnt,
                pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null,
                pAllSearch, "화주,화주코드,화주명");
            break;
        case 3:
            udc_kcg.ilCommonPopUp(scwin.callbackKcg,
                pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null,
                pAllSearch, null);
            break;
        case 4:
            udc_comm.ilCommonPopUp(scwin.callbackComm,
                pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null,
                pAllSearch, null);
            break;
        default:
            break;
    }
};

scwin.callbackYard = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_yardCd, txt_yardNm);
};

scwin.callbackStockClnt = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_stockClntCd, txt_stockClntNm);
};

scwin.callbackKcg = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_kcgCd, txt_kcgNm);
};

scwin.callbackComm = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_commCd, txt_commNm);
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    else
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
};

scwin.f_openPopUp = function(disGubun, chgGubun) {
    switch (disGubun) {
        case 2:
            udc_yard.ilCommonPopUp(scwin.callbackPopUpYard,
                ed_yardCd.getValue(), txt_yardNm.getValue(), chgGubun, "5", null, "150,170", null, null, "440", "500", null, null);
            break;
        case 3:
            udc_stockClnt.ilCommonPopUp(scwin.callbackPopUpStockClnt,
                ed_stockClntCd.getValue(), txt_stockClntNm.getValue(), chgGubun, "5", null, "150,170", null, null, "440", "500", null, null);
            break;
        case 4:
            udc_kcg.ilCommonPopUp(scwin.callbackPopUpKcg,
                ed_kcgCd.getValue(), txt_kcgNm.getValue(), chgGubun, "5", null, "150,170", null, null, "440", "500", null, null);
            break;
        case 5:
            udc_comm.ilCommonPopUp(scwin.callbackPopUpComm,
                ed_commCd.getValue(), txt_commNm.getValue(), chgGubun, "5", null, "150,170", null, "3,4", "440", "500", null, null);
            break;
        default:
            break;
    }
};

scwin.callbackPopUpYard = function(rtnList) {
    if (rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_yardCd, txt_yardNm);
    }
};

scwin.callbackPopUpStockClnt = function(rtnList) {
    if (rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_stockClntCd, txt_stockClntNm);
    }
};

scwin.callbackPopUpKcg = function(rtnList) {
    if (rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_kcgCd, txt_kcgNm);
    }
};

scwin.callbackPopUpComm = function(rtnList) {
    if (rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_commCd, txt_commNm);
    }
};

scwin.f_validateDate = async function() {
    let chFlag = [false, false, false, false];

    if (ed_term1From.getValue() != "" && ed_term1To.getValue() != "") {
        if (Number(ed_term1From.getValue()) > Number(ed_term1To.getValue())) {
            await $c.win.alert("보유기간 1: 시작일자가 종료일자 이전이어야 합니다.");
            ed_term1From.setFocus();
            return;
        }
        chFlag[0] = true;
    }

    if (ed_term2From.getValue() != "" && ed_term2To.getValue() != "") {
        if (Number(ed_term2From.getValue().trim()) > Number(ed_term2To.getValue().trim())) {
            await $c.win.alert("보유기간 2: 시작일자가 종료일자 이전이어야 합니다.");
            ed_term2From.setFocus();
            return;
        }
        chFlag[1] = true;
    }

    if (ed_term3From.getValue() != "" && ed_term3To.getValue() != "") {
        if (Number(ed_term3From.getValue().trim()) > Number(ed_term3To.getValue().trim())) {
            await $c.win.alert("보유기간 3: 시작일자가 종료일자 이전이어야 합니다.");
            ed_term3From.setFocus();
            return;
        }
        chFlag[2] = true;
    }

    if (ed_term4From.getValue() != "")
        chFlag[3] = true;

    if (chFlag[0]) {
        if (chFlag[1]) {
            if (Number(ed_term1To.getValue().trim()) >= Number(ed_term2From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 1과 2의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?"))) return;
            } else if (Number(ed_term1To.getValue().trim()) + 1 != Number(ed_term2From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 1과 2의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?"))) return;
            }
        } else if (chFlag[2]) {
            if (Number(ed_term1To.getValue().trim()) >= Number(ed_term3From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 1과 3의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?"))) return;
            } else if (Number(ed_term1To.getValue().trim()) + 1 != Number(ed_term3From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 1과 3의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?"))) return;
            }
        } else if (chFlag[3]) {
            if (Number(ed_term1To.getValue().trim()) > Number(ed_term4From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 1과 4의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?"))) return;
            } else if (Number(ed_term1To.getValue().trim()) + 1 != Number(ed_term4From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 1과 4의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?"))) return;
            }
        }
    }
    if (chFlag[1]) {
        if (chFlag[2]) {
            if (Number(ed_term2To.getValue().trim()) >= Number(ed_term3From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 2와 3의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?"))) return;
            } else if (Number(ed_term2To.getValue().trim()) + 1 != Number(ed_term3From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 2와 3의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?"))) return;
            }
        } else if (chFlag[3]) {
            if (Number(ed_term2To.getValue().trim()) > Number(ed_term4From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 2와 4의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?"))) return;
            } else if (Number(ed_term2To.getValue().trim()) + 1 != Number(ed_term4From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 2와 4의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?"))) return;
            }
        }
    }
    if (chFlag[2]) {
        if (chFlag[3]) {
            if (Number(ed_term3To.getValue().trim()) > Number(ed_term4From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 3과 4의 검색 기간이  중복되었습니다.\n계속 하시겠습니까?"))) return;
            } else if (Number(ed_term3To.getValue().trim()) != Number(ed_term4From.getValue().trim())) {
                if (!(await $c.win.confirm("보유기간 3과 4의 검색 기간이 연속되어 있지 않습니다.\n계속 하시겠습니까?"))) return;
            }
        }
    }

    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_columnShowHide = function() {
    if (ed_term1From.getValue() != "" && ed_term1To.getValue() != "") {
        gr_stockPresent.setColumnVisible("stockQty1", true);
        gr_stockPresent.setColumnVisible("stockWt1", true);
        gr_stockPresent.setColumnVisible("stockCbm1", true);
    } else {
        gr_stockPresent.setColumnVisible("stockQty1", false);
        gr_stockPresent.setColumnVisible("stockWt1", false);
        gr_stockPresent.setColumnVisible("stockCbm1", false);
    }

    if (ed_term2From.getValue() != "" && ed_term2To.getValue() != "") {
        gr_stockPresent.setColumnVisible("stockQty2", true);
        gr_stockPresent.setColumnVisible("stockWt2", true);
        gr_stockPresent.setColumnVisible("stockCbm2", true);
    } else {
        gr_stockPresent.setColumnVisible("stockQty2", false);
        gr_stockPresent.setColumnVisible("stockWt2", false);
        gr_stockPresent.setColumnVisible("stockCbm2", false);
    }

    if (ed_term3From.getValue() != "" && ed_term3To.getValue() != "") {
        gr_stockPresent.setColumnVisible("stockQty3", true);
        gr_stockPresent.setColumnVisible("stockWt3", true);
        gr_stockPresent.setColumnVisible("stockCbm3", true);
    } else {
        gr_stockPresent.setColumnVisible("stockQty3", false);
        gr_stockPresent.setColumnVisible("stockWt3", false);
        gr_stockPresent.setColumnVisible("stockCbm3", false);
    }

    if (ed_term4From.getValue() != "") {
        gr_stockPresent.setColumnVisible("stockQty4", true);
        gr_stockPresent.setColumnVisible("stockWt4", true);
        gr_stockPresent.setColumnVisible("stockCbm4", true);
    } else {
        gr_stockPresent.setColumnVisible("stockQty4", false);
        gr_stockPresent.setColumnVisible("stockWt4", false);
        gr_stockPresent.setColumnVisible("stockCbm4", false);
    }
};

scwin.f_toExcel1 = function() {
    $c.data.downloadGridViewExcel(gr_stockPresent, {"fileName": "보유기간별 벌크 재고현황.xlsx", "sheetName": "보유기간별 벌크 재고현황"});
};

scwin.f_clsCondRdoShowHide = function() {
    if (rd_cls.getValue() == "1")
        lc_con_accfCargoStd.setDisabled(true);
    else if (rd_cls.getValue() == "2")
        lc_con_accfCargoStd.setDisabled(false);
};

scwin.f_UnitChage = function(flag) {
    let total_cnt = ds_stockPresent.getRowCount();
    let change_unitState = co_lc_unitCd.getValue();

    if (change_unitState == "01") {
        gr_stockPresent.setColumnProp("stockWt1", "header", "중량<br/>(Ton)");
        gr_stockPresent.setColumnProp("stockWt2", "header", "중량<br/>(Ton)");
        gr_stockPresent.setColumnProp("stockWt3", "header", "중량<br/>(Ton)");
        gr_stockPresent.setColumnProp("stockWt4", "header", "중량<br/>(Ton)");
        gr_stockPresent.setColumnProp("stockWtTotal", "header", "중량<br/>(Ton)");
    } else {
        gr_stockPresent.setColumnProp("stockWt1", "header", "중량<br/>(Kg)");
        gr_stockPresent.setColumnProp("stockWt2", "header", "중량<br/>(Kg)");
        gr_stockPresent.setColumnProp("stockWt3", "header", "중량<br/>(Kg)");
        gr_stockPresent.setColumnProp("stockWt4", "header", "중량<br/>(Kg)");
        gr_stockPresent.setColumnProp("stockWtTotal", "header", "중량<br/>(Kg)");
    }

    if (flag == 1) {
        if (change_unitState == "01") {
            for (let i = 0; i < total_cnt; i++) {
                ds_stockPresent.setCellData(i, "stockWt1", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt1") == null ? 0 : ds_stockPresent.getCellData(i, "stockWt1"), "KG", "TON"));
                ds_stockPresent.setCellData(i, "stockWt2", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt2") == null ? 0 : ds_stockPresent.getCellData(i, "stockWt2"), "KG", "TON"));
                ds_stockPresent.setCellData(i, "stockWt3", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt3") == null ? 0 : ds_stockPresent.getCellData(i, "stockWt3"), "KG", "TON"));
                ds_stockPresent.setCellData(i, "stockWt4", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt4") == null ? 0 : ds_stockPresent.getCellData(i, "stockWt4"), "KG", "TON"));
                ds_stockPresent.setCellData(i, "stockWtTotal", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWtTotal") == null ? 0 : ds_stockPresent.getCellData(i, "stockWtTotal"), "KG", "TON"));
            }
        }
        scwin.cur_unitState = change_unitState;
    } else {
        if (scwin.cur_unitState != change_unitState) {
            for (let i = 0; i < total_cnt; i++) {
                if (change_unitState == "01") {
                    ds_stockPresent.setCellData(i, "stockWt1", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt1"), "KG", "TON"));
                    ds_stockPresent.setCellData(i, "stockWt2", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt2"), "KG", "TON"));
                    ds_stockPresent.setCellData(i, "stockWt3", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt3"), "KG", "TON"));
                    ds_stockPresent.setCellData(i, "stockWt4", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt4"), "KG", "TON"));
                    ds_stockPresent.setCellData(i, "stockWtTotal", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWtTotal"), "KG", "TON"));
                } else {
                    ds_stockPresent.setCellData(i, "stockWt1", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt1"), "TON", "KG"));
                    ds_stockPresent.setCellData(i, "stockWt2", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt2"), "TON", "KG"));
                    ds_stockPresent.setCellData(i, "stockWt3", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt3"), "TON", "KG"));
                    ds_stockPresent.setCellData(i, "stockWt4", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWt4"), "TON", "KG"));
                    ds_stockPresent.setCellData(i, "stockWtTotal", $c.gus.cfConvert2Weight(ds_stockPresent.getCellData(i, "stockWtTotal"), "TON", "KG"));
                }
            }
            scwin.cur_unitState = change_unitState;
        }
    }
};

scwin.sbm_retrieve_submitdone = async function(e) {
    scwin.f_columnShowHide();

    let i = 0;
    while (ds_stockPresent.getRowCount() > i) {
        if (Number(String(ds_stockPresent.getCellData(i, "stockQtyTotal")).trim()) == 0 &&
            Number(String(ds_stockPresent.getCellData(i, "stockWtTotal")).trim()) == 0 &&
            Number(String(ds_stockPresent.getCellData(i, "stockCbmTotal")).trim()) == 0) {
            ds_stockPresent.removeRow(i);
        } else {
            i++;
        }
    }

    if (ds_stockPresent.getRowCount() == 0) {
        await $c.win.alert("조회된 데이터가 없습니다.");
    }

    spa_totalRow.setValue(ds_stockPresent.getRowCount());
    scwin.f_UnitChage(1);
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_lobranCd_submitdone = function(e) {
    let idx = -1;
    for (let i = 0; i < ds_lobranCd.getRowCount(); i++) {
        if (ds_lobranCd.getCellData(i, "lobranCd") == scwin.loUpperLobranCd) {
            idx = i;
            break;
        }
    }
    if (idx > 0) {
        lc_branch.setSelectedIndex(idx);
    } else {
        lc_branch.setSelectedIndex(0);
    }
};

scwin.sbm_lobranCd_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.co_lc_unitCd_onchange = function(e) {
    scwin.f_UnitChage(2);
};

scwin.gr_stockPresent_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (rowIndex == -1) {
        switch (columnId) {
            case "wrkPlNm":
                ds_stockPresent.sort("wrkPlNm", "asc");
                break;
            case "stockClntNm":
                ds_stockPresent.sort("stockClntNm", "asc");
                break;
            case "kcgNm":
                ds_stockPresent.sort("kcgNm", "asc");
                break;
            case "commNm":
                ds_stockPresent.sort("commNm", "asc");
                break;
            default:
                break;
        }
    }
};

scwin.ed_yardCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_yardCd, txt_yardNm, 1, true);
};

scwin.ed_stockClntCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_stockClntCd, txt_stockClntNm, 2, true);
};

scwin.ed_kcgCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_kcgCd, txt_kcgNm, 3, true);
};

scwin.ed_commCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_commCd, txt_commNm, 4, true);
};

scwin.rd_cls_onviewchange = function(e) {
    scwin.f_clsCondRdoShowHide();
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_refresh_onclick = function(e) {
    scwin.f_InitObjects();
};
